// Aggregate and normalize all data sources into unified intelligence objects
const items = $input.all();
const config = $('Set Weekly Config').first().json;
const weekDate = config.weekDate;

const normalized = [];

for (const item of items) {
  const d = item.json;

  // Determine source type and competitor
  let source = 'web';
  let competitorName = 'Unknown';
  let content = '';
  let itemUrl = '';
  let pubDate = weekDate;

  if (d.link || d.guid || d.pubDate) {
    // RSS item
    source = 'rss';
    competitorName = d.categories?.join(', ') || 'Industry';
    content = (d.contentSnippet || d.content || d.description || '').substring(0, 800);
    itemUrl = d.link || d.guid || '';
    pubDate = d.pubDate || weekDate;
  } else {
    // Web scraped item - try to match by pageTitle context
    const title = (d.pageTitle || '').toLowerCase();
    if (title.includes(config.competitor1Name?.toLowerCase() || 'competitor a')) {
      competitorName = config.competitor1Name;
      itemUrl = config.competitor1Url;
    } else if (title.includes(config.competitor2Name?.toLowerCase() || 'competitor b')) {
      competitorName = config.competitor2Name;
      itemUrl = config.competitor2Url;
    } else if (title.includes(config.competitor3Name?.toLowerCase() || 'competitor c')) {
      competitorName = config.competitor3Name;
      itemUrl = config.competitor3Url;
    } else {
      // Assign based on order — each node sends one item so cycle through
      competitorName = config.competitor1Name || 'Competitor';
    }

    const parts = [
      d.pageTitle || '',
      d.h1Headings || '',
      d.pricingContent || '',
      d.featureContent || '',
      d.mainContent || ''
    ].filter(Boolean);
    content = parts.join(' | ').substring(0, 1200);
  }

  if (content.trim()) {
    normalized.push({
      source,
      competitor: competitorName,
      title: d.title || d.pageTitle || 'No Title',
      content: content.trim(),
      url: itemUrl,
      pubDate,
      weekDate
    });
  }
}

return [{ json: { allData: normalized, totalItems: normalized.length, weekDate, collectedAt: new Date().toISOString() } }];

// Compare this week's data with last week and prepare Scout brief
const items = $input.all();
const config = $('Set Weekly Config').first().json;

// Separate current week data from history
let currentData = null;
const previousRows = [];

for (const item of items) {
  const d = item.json;
  if (d.allData) {
    // This is from Aggregate All Sources
    currentData = d;
  } else if (d.weekDate === config.previousWeekDate) {
    previousRows.push(d);
  }
}

if (!currentData) {
  // Fallback: use whatever is available
  const firstItem = items[0]?.json || {};
  currentData = { allData: [], totalItems: 0, weekDate: config.weekDate };
}

// Build comparison context
const comparisonContext = previousRows.length > 0
  ? `PREVIOUS WEEK DATA (${config.previousWeekDate}):\n${JSON.stringify(previousRows.slice(0, 20), null, 2)}`
  : 'No previous week data available for comparison (first run or data gap).';

// Token estimation
const dataStr = JSON.stringify(currentData.allData);
const estimatedTokens = Math.round(dataStr.length / 4);
const tokenWarning = estimatedTokens > 8000 ? ' [TRUNCATED FOR TOKEN LIMIT]' : '';

// Truncate data if needed
const dataForAgent = currentData.allData.slice(0, 30).map(item => ({
  source: item.source,
  competitor: item.competitor,
  title: item.title.substring(0, 100),
  content: item.content.substring(0, 600),
  url: item.url,
  pubDate: item.pubDate
}));

return [{
  json: {
    weekDate: config.weekDate,
    previousWeekDate: config.previousWeekDate,
    yourCompany: config.yourCompanyName,
    industry: config.yourIndustry,
    groqModel: config.groqModel,
    maxTokens: config.maxTokens,
    currentData: dataForAgent,
    totalSourcesCollected: currentData.totalItems,
    comparisonContext,
    estimatedInputTokens: estimatedTokens + tokenWarning,
    previousDataAvailable: previousRows.length > 0
  }
}];

// Build Scout Agent request payload
const d = $input.first().json;

const SCOUT_SYSTEM_PROMPT = `You are the Scout Agent in a Multi-Agent Competitor Intelligence System for ${d.yourCompany} in the ${d.industry} space.

Your mission: Organize and summarize raw competitor data collected this week (${d.weekDate}) into a structured intelligence brief.

TASKS:
1. Review ALL raw data items and identify meaningful intelligence signals
2. Categorize findings by competitor
3. Flag significant changes: new features, pricing shifts, messaging updates, new blog themes, product launches
4. Assess data completeness and flag gaps
5. Compare with previous week context if available
6. Produce a clean, structured JSON brief for the Analyst Agent

RULES:
- Respond ONLY with valid JSON (no markdown, no extra text)
- Be factual and evidence-based — cite where each observation comes from
- Flag confidence level for each finding
- Keep competitor summaries under 200 words each
- Identify the 3 most significant developments of the week

OUTPUT FORMAT:
{
  "intelligence_week": "${d.weekDate}",
  "previous_week": "${d.previousWeekDate}",
  "sources_analyzed": <number>,
  "competitors": [
    {
      "name": "<competitor name>",
      "key_changes_this_week": ["change 1", "change 2"],
      "new_features_detected": ["feature"],
      "pricing_signals": "<pricing observations or 'no data'>",
      "content_themes": ["theme 1", "theme 2"],
      "market_positioning": "<how they position themselves>",
      "notable_urls": ["url1"],
      "confidence": "high/medium/low",
      "vs_last_week": "<what changed vs previous week or 'no comparison data'>"
    }
  ],
  "market_signals": [
    {
      "signal": "<description>",
      "source": "<where found>",
      "significance": "high/medium/low",
      "potential_impact_on_us": "<how this affects ${d.yourCompany}>"
    }
  ],
  "data_quality": {
    "completeness": "high/medium/low",
    "gaps": ["missing data 1"],
    "recommendations": ["improve X data collection"]
  },
  "top_3_developments": [
    {"rank": 1, "development": "<most important thing>", "urgency": "high/medium/low"}
  ],
  "week_summary": "<2-3 sentence executive summary>"
}`;

const userContent = `CURRENT WEEK DATA (${d.weekDate}):\n${JSON.stringify(d.currentData, null, 2)}\n\n${d.comparisonContext}`;

return [{
  json: {
    requestPayload: {
      model: d.groqModel,
      messages: [
        { role: 'system', content: SCOUT_SYSTEM_PROMPT },
        { role: 'user', content: userContent }
      ],
      temperature: 0.2,
      max_tokens: d.maxTokens
    },
    agentMeta: { agent: 'Scout', week: d.weekDate, groqModel: d.groqModel }
  }
}];

// Parse Scout Agent response and extract intelligence brief
const response = $input.first().json;
const agentMeta = $('Prepare Scout Request').first().json.agentMeta;
const compareData = $('Compare & Prepare Brief').first().json;

let scoutOutput = '';
let parsedBrief = null;

try {
  const rawContent = response.choices?.[0]?.message?.content || '';
  scoutOutput = rawContent;

  // Try to extract JSON from the response
  const jsonMatch = rawContent.match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    parsedBrief = JSON.parse(jsonMatch[0]);
  }
} catch (e) {
  parsedBrief = { parse_error: e.message, raw: scoutOutput.substring(0, 500) };
}

const usage = response.usage || {};
const tokenCost = {
  prompt_tokens: usage.prompt_tokens || 0,
  completion_tokens: usage.completion_tokens || 0,
  total_tokens: usage.total_tokens || 0,
  estimated_cost_usd: '$0.00 (Groq free tier)'
};

return [{
  json: {
    scoutBrief: parsedBrief || { raw: scoutOutput },
    scoutRawOutput: scoutOutput,
    weekDate: compareData.weekDate,
    previousWeekDate: compareData.previousWeekDate,
    yourCompany: compareData.yourCompany,
    industry: compareData.industry,
    groqModel: compareData.groqModel,
    maxTokens: compareData.maxTokens,
    tokenUsage: tokenCost,
    agentChain: ['Scout']
  }
}];

// Build Analyst Agent request
const d = $input.first().json;

const ANALYST_SYSTEM_PROMPT = `You are the Analyst Agent in a Multi-Agent Competitor Intelligence System for ${d.yourCompany} in the ${d.industry} space.

You receive a structured intelligence brief from the Scout Agent and produce a deep analytical assessment.

Your role:
1. Analyze competitive positioning and strategy shifts with evidence
2. Identify patterns, trends, and trajectories across competitors
3. Assess product development directions and feature velocity
4. Analyze messaging, GTM changes, and audience targeting shifts
5. Identify competitive threats (scored by severity) and opportunities
6. Estimate competitor growth signals (hiring signals, content volume, new integrations)
7. Predict likely next moves for each competitor

RULES:
- Respond ONLY with valid JSON
- Every claim must cite a specific piece of evidence from the Scout brief
- Use a 1-10 severity scale for threats
- Provide confidence levels (high/medium/low) for predictions
- Be analytical and forward-looking, not just descriptive

OUTPUT FORMAT:
{
  "analysis_date": "${d.weekDate}",
  "analyst_version": "1.0",
  "competitive_landscape": {
    "overall_intensity": "high/medium/low",
    "market_phase": "growth/maturity/disruption/consolidation",
    "key_dynamics": ["dynamic 1", "dynamic 2"]
  },
  "competitor_deep_dives": [
    {
      "competitor": "<name>",
      "strategic_direction": "<what they appear to be building toward>",
      "feature_velocity": "accelerating/steady/slowing",
      "pricing_strategy": "<observed pricing approach>",
      "target_customer_shift": "<who they're moving toward>",
      "predicted_next_moves": ["move 1 (confidence: high)"],
      "evidence_base": ["evidence 1 from Scout brief"]
    }
  ],
  "threat_matrix": [
    {
      "threat": "<description>",
      "competitor": "<source>",
      "severity": 1-10,
      "timeline": "immediate/3-6 months/6-12 months/12+ months",
      "evidence": "<supporting data>",
      "recommended_response": "<initial suggestion>"
    }
  ],
  "opportunity_matrix": [
    {
      "opportunity": "<description>",
      "type": "gap/positioning/timing/technology",
      "potential_impact": "high/medium/low",
      "evidence": "<why this opportunity exists>",
      "capture_window": "<how long we have>"
    }
  ],
  "trend_analysis": [
    {
      "trend": "<description>",
      "direction": "accelerating/emerging/declining",
      "implications": "<what this means for ${d.yourCompany}>"
    }
  ],
  "key_insights": ["insight 1", "insight 2", "insight 3"],
  "analyst_confidence": "high/medium/low",
  "data_limitations": ["limitation 1"]
}`;

return [{
  json: {
    requestPayload: {
      model: d.groqModel,
      messages: [
        { role: 'system', content: ANALYST_SYSTEM_PROMPT },
        { role: 'user', content: `Perform deep analysis on this Scout intelligence brief:\n\n${JSON.stringify(d.scoutBrief, null, 2)}` }
      ],
      temperature: 0.3,
      max_tokens: d.maxTokens
    },
    passThrough: d
  }
}];

const response = $input.first().json;
const passThrough = $('Prepare Analyst Request').first().json.passThrough;

let analystOutput = '';
let parsedAnalysis = null;

try {
  const rawContent = response.choices?.[0]?.message?.content || '';
  analystOutput = rawContent;
  const jsonMatch = rawContent.match(/\{[\s\S]*\}/);
  if (jsonMatch) parsedAnalysis = JSON.parse(jsonMatch[0]);
} catch (e) {
  parsedAnalysis = { parse_error: e.message, raw: analystOutput.substring(0, 500) };
}

return [{
  json: {
    ...passThrough,
    analystReport: parsedAnalysis || { raw: analystOutput },
    analystRawOutput: analystOutput,
    tokenUsage: {
      ...passThrough.tokenUsage,
      analyst_tokens: response.usage?.total_tokens || 0
    },
    agentChain: [...(passThrough.agentChain || []), 'Analyst']
  }
}];

// Build Critic Agent request
const d = $input.first().json;

const CRITIC_SYSTEM_PROMPT = `You are the Critic Agent in a Multi-Agent Competitor Intelligence System for ${d.yourCompany}.

Your role is quality control and intellectual rigor. You receive both the Scout brief AND the Analyst's assessment, and your job is to challenge, refine, and improve the analysis.

CRITIQUE FRAMEWORK:
1. EVIDENCE CHECK: Flag every claim that lacks supporting data from the Scout brief
2. BIAS DETECTION: Identify confirmation bias, availability bias, or overconfidence
3. ALTERNATIVE HYPOTHESES: Offer competing explanations for observed competitor behavior
4. SEVERITY CALIBRATION: Challenge threat/opportunity scores that seem inflated or deflated
5. GAP ANALYSIS: Identify important angles the Analyst missed entirely
6. PREDICTION STRESS-TEST: Which predictions are based on weak evidence?
7. ACTIONABILITY REVIEW: Flag recommendations that are too vague or impractical

RULES:
- Respond ONLY with valid JSON
- Be critical but constructive — your goal is to improve, not to dismiss
- Every critique must specify the exact claim being challenged
- Provide a revised confidence rating for each major finding
- Generate at least 2 alternative interpretations for the top findings

OUTPUT FORMAT:
{
  "critique_date": "${d.weekDate}",
  "overall_analysis_quality": "excellent/good/fair/poor",
  "quality_score": 1-10,
  "strengths": ["strength 1", "strength 2"],
  "critical_issues": [
    {
      "issue": "<what the Analyst got wrong or overstated>",
      "original_claim": "<the specific claim being challenged>",
      "why_problematic": "<evidence-based reasoning>",
      "severity": "high/medium/low"
    }
  ],
  "unsupported_claims": [
    {
      "claim": "<the claim>",
      "why_unsupported": "<what evidence is missing>",
      "required_evidence": "<what would validate this claim>"
    }
  ],
  "alternative_interpretations": [
    {
      "original_finding": "<what Analyst said>",
      "alternative": "<different explanation>",
      "plausibility": "high/medium/low",
      "evidence": "<what supports this alternative>"
    }
  ],
  "recalibrated_threats": [
    {
      "threat": "<description>",
      "analyst_severity": <original score>,
      "critic_severity": <revised score>,
      "rationale": "<why recalibrated>"
    }
  ],
  "missed_angles": ["important angle 1", "important angle 2"],
  "recommended_refinements": ["refinement 1", "refinement 2"],
  "validated_findings": ["finding the Analyst got right with strong evidence"]
}`;

return [{
  json: {
    requestPayload: {
      model: d.groqModel,
      messages: [
        { role: 'system', content: CRITIC_SYSTEM_PROMPT },
        { role: 'user', content: `Review this intelligence chain:\n\nSCOUT BRIEF:\n${JSON.stringify(d.scoutBrief, null, 2)}\n\nANALYST REPORT:\n${JSON.stringify(d.analystReport, null, 2)}` }
      ],
      temperature: 0.4,
      max_tokens: d.maxTokens
    },
    passThrough: d
  }
}];

const response = $input.first().json;
const passThrough = $('Prepare Critic Request').first().json.passThrough;

let criticOutput = '';
let parsedCritique = null;

try {
  const rawContent = response.choices?.[0]?.message?.content || '';
  criticOutput = rawContent;
  const jsonMatch = rawContent.match(/\{[\s\S]*\}/);
  if (jsonMatch) parsedCritique = JSON.parse(jsonMatch[0]);
} catch (e) {
  parsedCritique = { parse_error: e.message, raw: criticOutput.substring(0, 500) };
}

return [{
  json: {
    ...passThrough,
    critique: parsedCritique || { raw: criticOutput },
    criticRawOutput: criticOutput,
    tokenUsage: {
      ...passThrough.tokenUsage,
      critic_tokens: response.usage?.total_tokens || 0
    },
    agentChain: [...(passThrough.agentChain || []), 'Critic']
  }
}];

// Build Strategist Agent request
const d = $input.first().json;

const STRATEGIST_SYSTEM_PROMPT = `You are the Strategist Agent in a Multi-Agent Competitor Intelligence System for ${d.yourCompany} in the ${d.industry} space.

You have access to the full intelligence chain: Scout brief, Analyst deep dive, and Critic's quality review. Your role is to synthesize all of this into actionable strategic recommendations.

STRATEGIC FRAMEWORK:
1. IMMEDIATE ACTIONS (0-2 weeks): Urgent responses to high-severity threats
2. SHORT-TERM STRATEGY (1-3 months): Tactical moves to improve competitive position
3. MEDIUM-TERM STRATEGY (3-6 months): Strategic initiatives to capture opportunities
4. LONG-TERM POSITIONING (6-18 months): Structural advantages to build

GUIDING PRINCIPLES:
- Every recommendation must tie back to specific intelligence evidence
- Prioritize by impact × urgency matrix
- Consider resource constraints (assume typical startup/SMB resources)
- Include success metrics for each major recommendation
- Identify the single most important action this week

RULES:
- Respond ONLY with valid JSON
- Each action item must have: action, rationale, evidence_basis, timeline, priority (1-5), success_metric
- Use the Critic's refinements to correct any overstated threats
- Be specific — avoid generic advice like "improve product"

OUTPUT FORMAT:
{
  "strategy_date": "${d.weekDate}",
  "strategic_summary": "<2-3 sentence executive summary of the competitive situation>",
  "this_weeks_top_priority": {
    "action": "<single most important action>",
    "rationale": "<why this above all else>",
    "deadline": "<specific date or timeframe>",
    "owner": "<team/role responsible>"
  },
  "immediate_actions": [
    {
      "action": "<specific action>",
      "rationale": "<why>",
      "evidence_basis": "<intelligence that drives this>",
      "timeline": "<specific timeframe>",
      "priority": 1-5,
      "success_metric": "<how to measure success>",
      "estimated_effort": "low/medium/high"
    }
  ],
  "short_term_strategy": [
    {
      "initiative": "<strategic initiative>",
      "objective": "<what we're trying to achieve>",
      "competitive_rationale": "<which competitor dynamic drives this>",
      "key_milestones": ["milestone 1", "milestone 2"],
      "priority": 1-5
    }
  ],
  "medium_term_strategy": [
    {
      "initiative": "<strategic initiative>",
      "objective": "<what we're trying to achieve>",
      "timeline": "3-6 months",
      "priority": 1-5
    }
  ],
  "opportunities_to_capture": [
    {
      "opportunity": "<description>",
      "capture_method": "<how to capture it>",
      "window": "<how long available>",
      "estimated_impact": "high/medium/low"
    }
  ],
  "risks_to_mitigate": [
    {
      "risk": "<description>",
      "mitigation": "<specific mitigation action>",
      "contingency": "<if mitigation fails>",
      "severity": 1-10
    }
  ],
  "kpis_to_monitor_next_week": ["KPI 1", "KPI 2", "KPI 3"],
  "signals_to_watch": ["signal 1", "signal 2"]
}`;

return [{
  json: {
    requestPayload: {
      model: d.groqModel,
      messages: [
        { role: 'system', content: STRATEGIST_SYSTEM_PROMPT },
        { role: 'user', content: `Build strategy from this intelligence chain:\n\nSCOUT:\n${JSON.stringify(d.scoutBrief, null, 2)}\n\nANALYST:\n${JSON.stringify(d.analystReport, null, 2)}\n\nCRITIC REFINEMENTS:\n${JSON.stringify(d.critique, null, 2)}` }
      ],
      temperature: 0.5,
      max_tokens: d.maxTokens
    },
    passThrough: d
  }
}];

const response = $input.first().json;
const passThrough = $('Prepare Strategist Request').first().json.passThrough;

let stratOutput = '';
let parsedStrategy = null;

try {
  const rawContent = response.choices?.[0]?.message?.content || '';
  stratOutput = rawContent;
  const jsonMatch = rawContent.match(/\{[\s\S]*\}/);
  if (jsonMatch) parsedStrategy = JSON.parse(jsonMatch[0]);
} catch (e) {
  parsedStrategy = { parse_error: e.message, raw: stratOutput.substring(0, 500) };
}

return [{
  json: {
    ...passThrough,
    strategy: parsedStrategy || { raw: stratOutput },
    stratRawOutput: stratOutput,
    tokenUsage: {
      ...passThrough.tokenUsage,
      strategist_tokens: response.usage?.total_tokens || 0
    },
    agentChain: [...(passThrough.agentChain || []), 'Strategist']
  }
}];

// Format and finalize the complete intelligence report
const response = $input.first().json;
const d = $('Prepare Writer Request').first().json.passThrough;

const markdownReport = response.choices?.[0]?.message?.content || '# Report Generation Failed\n\nThe Writer Agent did not produce output.';

// Calculate total token usage
const writerTokens = response.usage?.total_tokens || 0;
const totalTokens = Object.values(d.tokenUsage || {}).reduce((sum, val) => {
  return sum + (typeof val === 'number' ? val : 0);
}, 0) + writerTokens;

// Build executive summary for notifications
const summaryLines = markdownReport.split('\n').slice(0, 30).join('\n');
const firstParagraph = markdownReport.match(/## Executive Summary\n([\s\S]*?)\n##/);
const execSummary = firstParagraph ? firstParagraph[1].trim().substring(0, 500) : summaryLines.substring(0, 500);

// Discord-safe summary (2000 char limit)
const discordSummary = `**Weekly Competitor Intelligence Report - ${d.weekDate}**\n\n${execSummary.substring(0, 1400)}...\n\n*Full report saved to Google Drive. Agents: Scout → Analyst → Critic → Strategist → Writer | Total tokens: ${totalTokens}*`;

// Telegram summary (4096 char limit, Markdown)
const telegramSummary = `*Weekly Intelligence Report - ${d.weekDate}*\n\n${execSummary.substring(0, 800)}\n\n_Full report saved. Agents: ${(d.agentChain || []).join(' → ')} → Writer_\nTokens used: ${totalTokens}`;

// Google Sheets row
const sheetsRow = {
  weekDate: d.weekDate,
  reportTitle: d.weekDate + ' Competitor Intelligence',
  totalSourcesCollected: d.scoutBrief?.sources_analyzed || 0,
  topThreatsCount: d.analystReport?.threat_matrix?.length || 0,
  topOpportunitiesCount: d.analystReport?.opportunity_matrix?.length || 0,
  analysisSummary: execSummary.substring(0, 500),
  totalTokensUsed: totalTokens,
  agentsCompleted: (d.agentChain || []).join(', ') + ', Writer',
  reportUrl: 'Pending Google Drive upload',
  generatedAt: new Date().toISOString()
};

return [{
  json: {
    markdownReport,
    discordSummary,
    telegramSummary,
    sheetsRow,
    weekDate: d.weekDate,
    reportTitle: d.weekDate + ' Competitor Intelligence Report',
    googleDriveFolderId: d.groqModel ? $('Set Weekly Config').first().json.googleDriveFolderId : '',
    googleSheetsId: $('Set Weekly Config').first().json.googleSheetsId,
    discordWebhookUrl: $('Set Weekly Config').first().json.discordWebhookUrl,
    telegramChatId: $('Set Weekly Config').first().json.telegramChatId,
    totalTokensUsed: totalTokens,
    tokenBreakdown: { ...d.tokenUsage, writer_tokens: writerTokens }
  }
}];

